1	package com.interview.lld.ratelimiter;
2	
3	import static org.junit.jupiter.api.Assertions.assertEquals;
4	import static org.junit.jupiter.api.Assertions.assertFalse;
5	import static org.junit.jupiter.api.Assertions.assertThrows;
6	import static org.junit.jupiter.api.Assertions.assertTrue;
7	
8	import java.util.concurrent.ConcurrentHashMap;
9	import java.util.concurrent.CyclicBarrier;
10	import java.util.concurrent.ExecutorService;
11	import java.util.concurrent.Executors;
12	import java.util.concurrent.TimeUnit;
13	import java.util.concurrent.atomic.AtomicInteger;
14	
15	import org.junit.jupiter.api.Test;
16	
17	import com.interview.lld.ratelimiter.gateway.FakeClock;
18	import com.interview.lld.ratelimiter.model.InvalidPolicyException;
19	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
20	import com.interview.lld.ratelimiter.model.UnknownCustomerException;
21	import com.interview.lld.ratelimiter.service.RateLimiterService;
22	import com.interview.lld.ratelimiter.service.ThreadSafeRateLimiterService;
23	import com.interview.lld.ratelimiter.strategy.StrategyFactory;
24	import com.interview.lld.ratelimiter.strategy.StrategyType;
25	
26	class RateLimiterServiceTest {
27	
28	    private static final long ONE_SECOND = 1_000_000_000L;
29	
30	    private RateLimiterService tokenBucket(FakeClock clock, long capacity, boolean autoRegister) {
31	        return new ThreadSafeRateLimiterService(
32	                clock, RateLimitPolicy.perSecond(capacity),
33	                new StrategyFactory(StrategyType.TOKEN_BUCKET), autoRegister);
34	    }
35	
36	    private RateLimiterService slidingWindow(FakeClock clock, long capacity) {
37	        return new ThreadSafeRateLimiterService(
38	                clock, RateLimitPolicy.perSecond(capacity),
39	                new StrategyFactory(StrategyType.SLIDING_WINDOW), true);
40	    }
41	
42	    // ── Happy path: token bucket allows the full burst then denies ───────────
43	    @Test
44	    void tokenBucketAllowsBurstUpToCapacityThenDenies() {
45	        FakeClock clock = new FakeClock(0);
46	        RateLimiterService limiter = tokenBucket(clock, 5, true);
47	
48	        for (int i = 0; i < 5; i++) {
49	            assertTrue(limiter.allow("alice"), "request " + i + " should pass");
50	        }
51	        assertFalse(limiter.allow("alice"), "6th request must be denied");
52	    }
53	
54	    // ── Refill: after one window the token bucket refills ────────────────────
55	    @Test
56	    void tokenBucketRefillsAfterWindow() {
57	        FakeClock clock = new FakeClock(0);
58	        RateLimiterService limiter = tokenBucket(clock, 2, true);
59	
60	        assertTrue(limiter.allow("bob"));
61	        assertTrue(limiter.allow("bob"));
62	        assertFalse(limiter.allow("bob"));
63	
64	        clock.advanceNanos(ONE_SECOND);
65	        assertTrue(limiter.allow("bob"), "bucket refilled after 1s");
66	    }
67	
68	    // ── Partial refill: half a window gives back half the tokens ─────────────
69	    @Test
70	    void tokenBucketPartialRefill() {
71	        FakeClock clock = new FakeClock(0);
72	        RateLimiterService limiter = tokenBucket(clock, 10, true);
73	
74	        for (int i = 0; i < 10; i++) {
75	            assertTrue(limiter.allow("c"));
76	        }
77	        assertFalse(limiter.allow("c"), "exhausted");
78	
79	        // Half a second at 10/s should drip back ~5 tokens.
80	        clock.advanceNanos(ONE_SECOND / 2);
81	        int allowed = 0;
82	        for (int i = 0; i < 10; i++) {
83	            if (limiter.allow("c")) {
84	                allowed++;
85	            }
86	        }
87	        assertEquals(5, allowed, "half a window refills half the tokens");
88	    }
89	
90	    // ── Sliding window: no double burst across the boundary ──────────────────
91	    @Test
92	    void slidingWindowBlocksBoundaryBurst() {
93	        FakeClock clock = new FakeClock(0);
94	        RateLimiterService limiter = slidingWindow(clock, 3);
95	
96	        for (int i = 0; i < 3; i++) {
97	            assertTrue(limiter.allow("carol"));
98	        }
99	        assertFalse(limiter.allow("carol"), "4th denied within window");
100	
101	        // Just before the window closes, still denied.
102	        clock.advanceNanos(ONE_SECOND - 1);
103	        assertFalse(limiter.allow("carol"), "still inside the window");
104	
105	        // Past the window: the original three slide out.
106	        clock.advanceNanos(2);
107	        assertTrue(limiter.allow("carol"), "old timestamps evicted");
108	    }
109	
110	    // ── Typed exception: unknown customer in strict mode ─────────────────────
111	    @Test
112	    void unknownCustomerRejectedInStrictMode() {
113	        FakeClock clock = new FakeClock(0);
114	        RateLimiterService limiter = tokenBucket(clock, 5, false);
115	
116	        assertThrows(UnknownCustomerException.class, () -> limiter.allow("ghost"));
117	    }
118	
119	    @Test
120	    void registeredCustomerAllowedInStrictMode() {
121	        FakeClock clock = new FakeClock(0);
122	        RateLimiterService limiter = tokenBucket(clock, 5, false);
123	
124	        limiter.register("known");
125	        assertTrue(limiter.allow("known"), "registered customer passes");
126	    }
127	
128	    // ── Typed exception: invalid policy at construction ──────────────────────
129	    @Test
130	    void invalidPolicyRejected() {
131	        assertThrows(InvalidPolicyException.class, () -> RateLimitPolicy.perSecond(0));
132	        assertThrows(InvalidPolicyException.class, () -> new RateLimitPolicy(5, 0));
133	        assertThrows(InvalidPolicyException.class, () -> new RateLimitPolicy(-1, ONE_SECOND));
134	    }
135	
136	    // ── Isolation: one customer exhausting does not affect another ───────────
137	    @Test
138	    void differentCustomersDoNotShareBudget() {
139	        FakeClock clock = new FakeClock(0);
140	        RateLimiterService limiter = tokenBucket(clock, 2, true);
141	
142	        assertTrue(limiter.allow("x"));
143	        assertTrue(limiter.allow("x"));
144	        assertFalse(limiter.allow("x"), "x exhausted");
145	
146	        assertTrue(limiter.allow("y"), "y unaffected by x");
147	        assertTrue(limiter.allow("y"));
148	        assertEquals(2, limiter.trackedCustomerCount(), "two distinct customers tracked");
149	    }
150	
151	    // ── Concurrency: 50 threads hammer ONE customer at the boundary ──────────
152	    // STRICT: exactly `limit` allowed, the rest denied, none throw.
153	    @Test
154	    void concurrentBurstOnOneCustomerAllowsExactlyLimit() throws Exception {
155	        int threads = 50;
156	        long limit = 10;
157	        FakeClock clock = new FakeClock(0);
158	        RateLimiterService limiter = tokenBucket(clock, limit, true);
159	        limiter.register("hot");
160	
161	        CyclicBarrier barrier = new CyclicBarrier(threads);
162	        AtomicInteger allowed = new AtomicInteger(0);
163	        AtomicInteger denied = new AtomicInteger(0);
164	        AtomicInteger errors = new AtomicInteger(0);
165	        ExecutorService pool = Executors.newFixedThreadPool(threads);
166	
167	        for (int i = 0; i < threads; i++) {
168	            pool.submit(() -> {
169	                try {
170	                    barrier.await(); // all 50 threads hit allow() at the same instant
171	                    if (limiter.allow("hot")) {
172	                        allowed.incrementAndGet();
173	                    } else {
174	                        denied.incrementAndGet();
175	                    }
176	                } catch (Exception e) {
177	                    errors.incrementAndGet();
178	                }
179	            });
180	        }
181	        pool.shutdown();
182	        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS), "all threads finished");
183	
184	        assertEquals(0, errors.get(), "no surprise exceptions");
185	        assertEquals(limit, allowed.get(), "exactly the limit allowed under the race");
186	        assertEquals(threads - limit, denied.get(), "everyone else denied");
187	    }
188	
189	    // ── Concurrency: many customers prove NO cross-contention ────────────────
190	    // Each of MANY customers, on its own thread, gets exactly its own limit —
191	    // proving customer A's traffic never consumed customer B's budget.
192	    @Test
193	    void manyCustomersHaveNoCrossContention() throws Exception {
194	        int customers = 40;
195	        long limit = 5;
196	        int attemptsPerCustomer = 12; // more than the limit
197	        FakeClock clock = new FakeClock(0);
198	        RateLimiterService limiter = tokenBucket(clock, limit, true);
199	
200	        CyclicBarrier barrier = new CyclicBarrier(customers);
201	        ConcurrentHashMap<String, Integer> allowedPerCustomer = new ConcurrentHashMap<>();
202	        ExecutorService pool = Executors.newFixedThreadPool(customers);
203	
204	        for (int c = 0; c < customers; c++) {
205	            String id = "cust-" + c;
206	            pool.submit(() -> {
207	                try {
208	                    barrier.await(); // all customers start at the same instant
209	                    int allowed = 0;
210	                    for (int i = 0; i < attemptsPerCustomer; i++) {
211	                        if (limiter.allow(id)) {
212	                            allowed++;
213	                        }
214	                    }
215	                    allowedPerCustomer.put(id, allowed);
216	                } catch (Exception e) {
217	                    throw new RuntimeException(e);
218	                }
219	            });
220	        }
221	        pool.shutdown();
222	        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS), "all threads finished");
223	
224	        assertEquals(customers, allowedPerCustomer.size(), "every customer recorded");
225	        for (var entry : allowedPerCustomer.entrySet()) {
226	            assertEquals(limit, entry.getValue().longValue(),
227	                    entry.getKey() + " must get exactly its own limit, no cross-contention");
228	        }
229	        assertEquals(customers, limiter.trackedCustomerCount(), "all customers tracked");
230	    }
231	}
