1	package com.interview.lld.ratelimiter.strategy;
2	
3	import com.interview.lld.ratelimiter.model.RateLimitPolicy;
4	
5	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
6	// Token bucket. Picture a bucket that holds at most `capacity` tokens and drips
7	// new tokens in at a steady rate. Every request takes one token; if the bucket is
8	// empty the request is denied. The clever part: we do NOT run a background timer
9	// to add tokens. Instead, each time a request comes in we look at how long it has
10	// been since the last request and pour in exactly that many tokens — "lazy
11	// refill". This means zero background threads and exact math.
12	// 🎙️ "Token bucket allows short bursts up to the bucket size, then settles to a
13	//      steady rate. I refill lazily — on each request I add the tokens that
14	//      should have dripped in since the last one, instead of running a timer."
15	//
16	// NOT thread-safe by itself — the service calls this only while holding that
17	// customer's lock, so the two fields below are never touched by two threads at once.
18	public final class TokenBucketStrategy implements RateLimitStrategy {
19	
20	    private final RateLimitPolicy policy;
21	    private final double maxTokens;
22	    private final double refillPerNano;
23	
24	    // WHY: tokens are a double, not an int. At a rate like 100/sec, between two
25	    //      requests 3 ms apart only 0.3 of a token drips in — we must carry that
26	    //      fraction forward, or fast callers would lose tokens to rounding.
27	    private double tokens;
28	    private long lastRefillNanos;
29	
30	    public TokenBucketStrategy(RateLimitPolicy policy, long startNanos) {
31	        this.policy = policy;
32	        this.maxTokens = policy.capacity();
33	        this.refillPerNano = policy.tokensPerNano();
34	        // WHY: start full. A brand-new customer should get their full burst
35	        //      allowance immediately, not have to wait for the bucket to fill.
36	        this.tokens = maxTokens;
37	        this.lastRefillNanos = startNanos;
38	    }
39	
40	    @Override
41	    public boolean tryAcquire(long nowNanos) {
42	        refill(nowNanos);
43	
44	        if (tokens >= 1.0) {
45	            // WHY: spend exactly one token. The fractional remainder stays in the
46	            //      bucket so it is not lost.
47	            tokens -= 1.0;
48	            return true;
49	        }
50	        return false;
51	    }
52	
53	    // WHY: lazy refill. Add (elapsed * rate) tokens, capped at the bucket size so
54	    //      an idle customer cannot accumulate unlimited credit and then flood.
55	    private void refill(long nowNanos) {
56	        long elapsed = nowNanos - lastRefillNanos;
57	
58	        if (elapsed <= 0) {
59	            // WHY: guard against a non-advancing or backwards clock — never add
60	            //      negative tokens, and do not move the timestamp backwards.
61	            return;
62	        }
63	        double refilled = elapsed * refillPerNano;
64	        tokens = Math.min(maxTokens, tokens + refilled);
65	        lastRefillNanos = nowNanos;
66	    }
67	}
