1	package com.interview.lld.ratelimiter.model;
2	
3	import java.util.concurrent.locks.ReentrantLock;
4	
5	import com.interview.lld.ratelimiter.strategy.RateLimitStrategy;
6	
7	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
8	// This is the unit of lock striping. Each customer gets ONE of these: their own
9	// limiting strategy AND their own lock. Because the lock lives here, two
10	// different customers never share a lock — customer A's flood of requests can
11	// never block customer B. That is the whole point of the design: isolate
12	// customers from each other.
13	// 🎙️ "Each customer owns one bucket: their strategy plus their own lock. The lock
14	//      is per-customer, so different customers never wait on each other — only
15	//      requests from the SAME customer serialize, and that is exactly what we
16	//      want because they share the same token count."
17	public final class CustomerBucket {
18	
19	    private final RateLimitStrategy strategy;
20	
21	    // WHY: a per-customer ReentrantLock. The strategy's state (tokens, timestamp
22	    //      log) is mutated on every request; this lock makes the read-modify-write
23	    //      one atomic step so two requests from the same customer cannot both see
24	    //      "one token left" and both spend it.
25	    // WHY: reentrant so the same thread could safely re-enter if a guarded method
26	    //      ever called another guarded method on this bucket.
27	    private final ReentrantLock lock = new ReentrantLock();
28	
29	    public CustomerBucket(RateLimitStrategy strategy) {
30	        this.strategy = strategy;
31	    }
32	
33	    // WHY: the strategy is package-visible only through this accessor; callers go
34	    //      through allow() on the service, never poke the strategy directly.
35	    public RateLimitStrategy strategy() {
36	        return strategy;
37	    }
38	
39	    public ReentrantLock lock() {
40	        return lock;
41	    }
42	}
