1	package com.interview.lld.ratelimiter.model;
2	
3	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
4	// The policy is the "rule book" for a customer: how many requests they get and
5	// how fast that allowance comes back. It is an object that never changes after
6	// it is created (a Java record), so two threads reading the same policy can
7	// never see it half-updated. Token bucket and sliding window both read these
8	// same two numbers — capacity and the time window — so one policy object feeds
9	// either strategy.
10	// 🎙️ "The policy is just two numbers — how many requests are allowed, and over
11	//      what window. It is immutable, so it is safe to share across all the
12	//      customer threads without any locking."
13	public record RateLimitPolicy(long capacity, long windowNanos) {
14	
15	    private static final long NANOS_PER_SECOND = 1_000_000_000L;
16	
17	    // WHY: compact constructor validates at build time. A zero capacity or a
18	    //      non-positive window is a configuration bug — we fail loudly here so it
19	    //      can never reach the hot path and behave unpredictably under load.
20	    public RateLimitPolicy {
21	        if (capacity <= 0) {
22	            throw new InvalidPolicyException("capacity must be positive, got " + capacity);
23	        }
24	        if (windowNanos <= 0) {
25	            throw new InvalidPolicyException("windowNanos must be positive, got " + windowNanos);
26	        }
27	    }
28	
29	    // WHY: a friendly factory so callers say "100 requests per second" instead of
30	    //      doing nanosecond arithmetic at every call site.
31	    public static RateLimitPolicy perSecond(long capacity) {
32	        return new RateLimitPolicy(capacity, NANOS_PER_SECOND);
33	    }
34	
35	    public static RateLimitPolicy of(long capacity, long windowSeconds) {
36	        return new RateLimitPolicy(capacity, windowSeconds * NANOS_PER_SECOND);
37	    }
38	
39	    // WHY: token bucket needs a refill RATE (tokens per nanosecond). Deriving it
40	    //      from capacity/window keeps the bucket and the window definition in
41	    //      sync — change the window and the refill rate follows automatically.
42	    public double tokensPerNano() {
43	        return (double) capacity / (double) windowNanos;
44	    }
45	}
