5	// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
6	// The test clock. It starts at some value and only moves when the test tells it
7	// to. This is what lets the test prove refill and window-roll behaviour without
8	// ever sleeping. It is thread-safe (AtomicLong) because the concurrency test has
9	// many threads reading "now" at the same moment.
10	// 🎙️ "This is the fake clock. The test moves it forward by hand with advance().
11	//      That is how I test 'one second later the bucket refilled' in microseconds
12	//      instead of actually waiting a second."
13	public final class FakeClock implements Clock {
14	
15	    private final AtomicLong nanos;
16	
17	    public FakeClock(long startNanos) {
18	        this.nanos = new AtomicLong(startNanos);
19	    }
20	
21	    @Override
22	    public long nowNanos() {
23	        return nanos.get();
24	    }
25	
26	    // WHY: tests call this to jump time forward. Atomic so the concurrency test
27	    //      can safely move the clock while worker threads read it.
28	    public void advanceNanos(long deltaNanos) {
29	        nanos.addAndGet(deltaNanos);
30	    }
31	}
