package com.interview.lld.ratelimiter;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.CyclicBarrier;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

import org.junit.jupiter.api.Test;

import com.interview.lld.ratelimiter.gateway.Clock;
import com.interview.lld.ratelimiter.gateway.FakeClock;
import com.interview.lld.ratelimiter.model.CustomerBucket;
import com.interview.lld.ratelimiter.model.InvalidPolicyException;
import com.interview.lld.ratelimiter.model.RateLimitPolicy;
import com.interview.lld.ratelimiter.model.UnknownCustomerException;
import com.interview.lld.ratelimiter.service.RateLimiterService;
import com.interview.lld.ratelimiter.service.ThreadSafeRateLimiterService;
import com.interview.lld.ratelimiter.strategy.RateLimitStrategy;
import com.interview.lld.ratelimiter.strategy.StrategyFactory;
import com.interview.lld.ratelimiter.strategy.StrategyType;

class RateLimiterServiceTest {

    private static final long ONE_SECOND = 1_000_000_000L;

    private RateLimiterService tokenBucket(FakeClock clock, long capacity, boolean autoRegister) {
        return new ThreadSafeRateLimiterService(
                clock, RateLimitPolicy.perSecond(capacity),
                new StrategyFactory(StrategyType.TOKEN_BUCKET), autoRegister);
    }

    private RateLimiterService slidingWindow(FakeClock clock, long capacity) {
        return new ThreadSafeRateLimiterService(
                clock, RateLimitPolicy.perSecond(capacity),
                new StrategyFactory(StrategyType.SLIDING_WINDOW), true);
    }

    // ── Happy path: token bucket allows the full burst then denies ───────────
    @Test
    void tokenBucketAllowsBurstUpToCapacityThenDenies() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 5, true);

        for (int i = 0; i < 5; i++) {
            assertTrue(limiter.allow("alice"), "request " + i + " should pass");
        }
        assertFalse(limiter.allow("alice"), "6th request must be denied");
    }

    // ── Refill: after one window the token bucket refills ────────────────────
    @Test
    void tokenBucketRefillsAfterWindow() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 2, true);

        assertTrue(limiter.allow("bob"));
        assertTrue(limiter.allow("bob"));
        assertFalse(limiter.allow("bob"));

        clock.advanceNanos(ONE_SECOND);
        assertTrue(limiter.allow("bob"), "bucket refilled after 1s");
    }

    // ── Partial refill: half a window gives back half the tokens ─────────────
    @Test
    void tokenBucketPartialRefill() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 10, true);

        for (int i = 0; i < 10; i++) {
            assertTrue(limiter.allow("c"));
        }
        assertFalse(limiter.allow("c"), "exhausted");

        // Half a second at 10/s should drip back ~5 tokens.
        clock.advanceNanos(ONE_SECOND / 2);
        int allowed = 0;
        for (int i = 0; i < 10; i++) {
            if (limiter.allow("c")) {
                allowed++;
            }
        }
        assertEquals(5, allowed, "half a window refills half the tokens");
    }

    // ── Sliding window: no double burst across the boundary ──────────────────
    @Test
    void slidingWindowBlocksBoundaryBurst() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = slidingWindow(clock, 3);

        for (int i = 0; i < 3; i++) {
            assertTrue(limiter.allow("carol"));
        }
        assertFalse(limiter.allow("carol"), "4th denied within window");

        // Just before the window closes, still denied.
        clock.advanceNanos(ONE_SECOND - 1);
        assertFalse(limiter.allow("carol"), "still inside the window");

        // Past the window: the original three slide out.
        clock.advanceNanos(2);
        assertTrue(limiter.allow("carol"), "old timestamps evicted");
    }

    // ── Typed exception: unknown customer in strict mode ─────────────────────
    @Test
    void unknownCustomerRejectedInStrictMode() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 5, false);

        assertThrows(UnknownCustomerException.class, () -> limiter.allow("ghost"));
    }

    @Test
    void registeredCustomerAllowedInStrictMode() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 5, false);

        limiter.register("known");
        assertTrue(limiter.allow("known"), "registered customer passes");
    }

    // ── Typed exception: invalid policy at construction ──────────────────────
    @Test
    void invalidPolicyRejected() {
        assertThrows(InvalidPolicyException.class, () -> RateLimitPolicy.perSecond(0));
        assertThrows(InvalidPolicyException.class, () -> new RateLimitPolicy(5, 0));
        assertThrows(InvalidPolicyException.class, () -> new RateLimitPolicy(-1, ONE_SECOND));
    }

    // ── Isolation: one customer exhausting does not affect another ───────────
    @Test
    void differentCustomersDoNotShareBudget() {
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = tokenBucket(clock, 2, true);

        assertTrue(limiter.allow("x"));
        assertTrue(limiter.allow("x"));
        assertFalse(limiter.allow("x"), "x exhausted");

        assertTrue(limiter.allow("y"), "y unaffected by x");
        assertTrue(limiter.allow("y"));
        assertEquals(2, limiter.trackedCustomerCount(), "two distinct customers tracked");
    }

    // ── Concurrency: 50 threads hammer ONE customer at the boundary ──────────
    // STRICT: exactly `limit` allowed, the rest denied, none throw.
    //
    // WHY the WIDE-WINDOW strategy: a real token bucket's critical section is a
    // few nanoseconds of double arithmetic, so on a fast machine threads almost
    // never actually overlap INSIDE tryAcquire — a missing lock would slip
    // through ~80% of the time and the test would prove nothing. We therefore
    // run the SAME service over a strategy whose check-then-spend has a forced
    // gap (yield + spin), so two unguarded threads reliably both observe "one
    // token left". Under the real per-customer lock, the gap is harmless: the
    // second thread simply waits. So this assertion now actually depends on the
    // lock — proven by basedServiceOverAllowsUnderWideRace below.
    @Test
    void concurrentBurstOnOneCustomerAllowsExactlyLimit() throws Exception {
        int threads = 50;
        long limit = 10;
        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = wideThreadSafe(clock, limit, true);
        limiter.register("hot");

        Result r = hammerOneCustomer(limiter, "hot", threads);

        assertEquals(0, r.errors.get(), "no surprise exceptions");
        assertEquals(limit, r.allowed.get(), "exactly the limit allowed under the race");
        assertEquals(threads - limit, r.denied.get(), "everyone else denied");
    }

    // ── Lock-in: the BASE (unlocked) service DOES over-allow under the SAME
    //    wide-window race ──────────────────────────────────────────────────────
    // This is the control. It proves the previous test's "exactly 10" is the
    // LOCK doing work, not luck. With no per-customer lock, the widened
    // check-then-act gap means several threads all see the last token and all
    // spend it, so MORE than the limit gets through. If this ever stopped
    // over-allowing, the concurrency test above would no longer be meaningful.
    @Test
    void baseServiceOverAllowsUnderWideRace() throws Exception {
        int threads = 50;
        long limit = 10;
        FakeClock clock = new FakeClock(0);
        RateLimiterService unlocked = wideBase(clock, limit, true); // NO gate hooks
        unlocked.register("hot");

        Result r = hammerOneCustomer(unlocked, "hot", threads);

        assertEquals(0, r.errors.get(), "the race over-grants, it does not throw");
        assertTrue(r.allowed.get() > limit,
                "without a per-customer lock the widened race MUST over-allow; got "
                        + r.allowed.get() + " (expected > " + limit + ")");
    }

    // ── Concurrency: MANY threads per customer prove NO cross-contention ─────
    // 40 customers x 5 threads each = 200 threads, all released on ONE barrier.
    // (a) >1 thread per customer means the per-customer lock is genuinely
    //     contended — using the wide-window strategy makes the unguarded race
    //     reliably over-grant, so the exact-limit assertion depends on the lock.
    // (b) Every customer must end with EXACTLY its own limit — a noisy customer
    //     hammered by 5 racing threads cannot bleed into, or steal from, any
    //     other customer's budget. That is the cross-contention guarantee, and
    //     it is now actually exercised (see contention assert at the end).
    @Test
    void manyCustomersHaveNoCrossContention() throws Exception {
        int customers = 40;
        int threadsPerCustomer = 5;
        long limit = 5;
        int attemptsPerThread = 4; // 5 threads x 4 = 20 attempts >> limit of 5
        int totalThreads = customers * threadsPerCustomer;

        FakeClock clock = new FakeClock(0);
        RateLimiterService limiter = wideThreadSafe(clock, limit, true);

        CyclicBarrier barrier = new CyclicBarrier(totalThreads);
        ConcurrentHashMap<String, AtomicInteger> allowedPerCustomer = new ConcurrentHashMap<>();
